#include <stdio.h>
#include <math.h>
int main() {
    int T, N;
    long long ai;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        long long P = 1;
        for (int i = 0; i < N; i++) {
            scanf("%lld", &ai);
            for (long long j = 2; j * j <= ai; j++) {
                if (ai % j == 0) {
                    int count = 0;
                    while (ai % j == 0) {
                        count++;
                        ai /= j;
                    }
                    if (count >= 2) {
                        P *= j;
                    }
                }
            }
            if (ai > 1) {
                P *= ai;
            }
        }
        printf("%lld\n", P);
    }
    return 0;
}

