        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long P = 1;
            for (int i = 0; i < N; i++) {
                long ai = sc.nextLong();
                for (long j = 2; j * j <= ai; j++) {
                    if (ai % j == 0) {
                        int count = 0;
                        while (ai % j == 0) {
                            count++;
                            ai /= j;
                        }
                        if (count >= 2) {
                            P *= j;
                        }
                    }
                }
                if (ai > 1) {
                    P *= ai;
                }
            }
            System.out.println(P);
        }
    }
}

